284	func (ac *ApiserverProxy) Proxy(c *gin.Context, backendAPIPrefix string) {
285		rp := httputil.ReverseProxy{
286			Transport: transport,
287			Director: func(request *http.Request) {
288				request.URL.Scheme = "http"
289				request.URL.Host = ac.address
290				path := request.URL.Path
291				path = strings.TrimPrefix(path, backendAPIPrefix)
292				path = "/tap/api/v1" + path
293				request.URL.Path = path
294			},
295		}
296		if len(ac.header) > 0 && c.Request.Header == nil {
297			c.Request.Header = ac.header
298		} else if len(ac.header) > 0 && c.Request.Header != nil {
299			for key, value := range ac.header {
300				c.Request.Header[key] = value
301			}
302		}
303		rp.ServeHTTP(c.Writer, c.Request)
304	}
305	
306	var (
307	
308		// Transport for apiserver client, can not use http.DefaultTransport
309		transport http.RoundTripper = &http.Transport{
310			TLSClientConfig: &tls.Config{
311				InsecureSkipVerify: true,
312			},
313			Proxy: http.ProxyFromEnvironment,
314			DialContext: defaultTransportDialContext(&net.Dialer{
315				Timeout:   40 * time.Second,
316				KeepAlive: 40 * time.Second,
317			}),
318			ForceAttemptHTTP2:     true,
319			MaxIdleConns:          100,
320			IdleConnTimeout:       90 * time.Second,
321			TLSHandshakeTimeout:   10 * time.Second,
322			ExpectContinueTimeout: 1 * time.Second,
323		}
324	)
