99	
100		log.Infof("Install release: namespace=%s, name=%s, repoChart=%s, version=%s, dryRun=%v", namespace, name, repoChart, version, dryRun)
101		if namespace == "" {
102			namespace = "default"
103		}
104		hc, err := c.HelmConfig(namespace)
105		if err != nil {
